"use client";

import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import styles from "./Section4Gallery.module.css";

gsap.registerPlugin(ScrollTrigger);

// 8 cards per row, duplicated for seamless infinite scroll
const FILM_CARDS_ROW_A = [
  { id: "a1", label: "Leaders Talk", tone: 1 },
  { id: "a2", label: "Khoảnh khắc", tone: 2 },
  { id: "a3", label: "Diễn giả",    tone: 3 },
  { id: "a4", label: "Hội trường",  tone: 1 },
  { id: "a5", label: "Workshop",    tone: 2 },
  { id: "a6", label: "Networking",  tone: 3 },
  { id: "a7", label: "Chia sẻ",    tone: 1 },
  { id: "a8", label: "Kết nối",    tone: 2 },
];
const FILM_CARDS_ROW_B = [
  { id: "b1", label: "Insight",     tone: 2 },
  { id: "b2", label: "Tư duy",      tone: 3 },
  { id: "b3", label: "Lãnh đạo",   tone: 1 },
  { id: "b4", label: "Thực chiến",  tone: 2 },
  { id: "b5", label: "Ý tưởng",    tone: 3 },
  { id: "b6", label: "Pain point",  tone: 1 },
  { id: "b7", label: "Khoảnh khắc",tone: 2 },
  { id: "b8", label: "Tầm nhìn",   tone: 3 },
];

function FilmCard({ tone }: { label: string; tone: number }) {
  return (
    <div className={`${styles.filmCard} ${styles[`tone${tone}`]}`}>
      <div className={styles.filmCardInner} />
    </div>
  );
}

export default function Section4Gallery() {
  const sectionRef  = useRef<HTMLDivElement>(null);
  const headerRef   = useRef<HTMLDivElement>(null);
  const stripRef    = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Reveal heading row (heading + subtext together)
    gsap.fromTo(headerRef.current,
      { opacity: 0, y: 30, filter: "blur(8px)" },
      {
        opacity: 1, y: 0, filter: "blur(0px)",
        duration: 0.9, ease: "power3.out",
        scrollTrigger: {
          trigger: "#section-4",
          start: "top 70%",
          toggleActions: "play none none reverse",
        },
      }
    );

    // Parallax lift of the whole film strip on scroll
    gsap.to(stripRef.current, {
      y: -60,
      ease: "none",
      scrollTrigger: {
        trigger: "#section-4",
        start: "top bottom",
        end: "bottom top",
        scrub: 1.2,
      },
    });
  }, []);

  return (
    <div ref={sectionRef} className={styles.wrapper}>
      {/* Heading */}
      <div ref={headerRef} className={styles.headerRow}>
        <h2 className={styles.heading} id="gallery-heading">
          Khoảnh khắc <span className={styles.headingAccent}>đáng nhớ</span>
        </h2>
        <p className={styles.subtext}>
          Những buổi chia sẻ, workshop và kết nối<br />
          giữa những nhà lãnh đạo hàng đầu.
        </p>
      </div>

      {/* Film strip — 3 rows going in alternating directions */}
      <div ref={stripRef} className={styles.filmOuter}>
        <div className={styles.filmInner}>

          {/* Row 1 — scroll left */}
          <div className={`${styles.filmRow} ${styles.rowLeft}`}>
            {[...FILM_CARDS_ROW_A, ...FILM_CARDS_ROW_A].map((c, i) => (
              <FilmCard key={`r1-${i}`} {...c} />
            ))}
          </div>

          {/* Row 2 — scroll right */}
          <div className={`${styles.filmRow} ${styles.rowRight}`}>
            {[...FILM_CARDS_ROW_B, ...FILM_CARDS_ROW_B].map((c, i) => (
              <FilmCard key={`r2-${i}`} {...c} />
            ))}
          </div>

          {/* Row 3 — scroll left (slower) */}
          <div className={`${styles.filmRow} ${styles.rowLeftSlow}`}>
            {[...FILM_CARDS_ROW_A, ...FILM_CARDS_ROW_A].map((c, i) => (
              <FilmCard key={`r3-${i}`} {...c} />
            ))}
          </div>

        </div>
      </div>
    </div>
  );
}
