"use client";

import { useEffect, useRef } from "react";
import gsap from "gsap";
import styles from "./HeroOverlay.module.css";

export default function HeroOverlay() {
  const titleRef   = useRef<HTMLHeadingElement>(null);
  const lineRef    = useRef<HTMLDivElement>(null);
  const taglineRef = useRef<HTMLParagraphElement>(null);
  const ctaGroupRef = useRef<HTMLDivElement>(null);
  const scrollRef  = useRef<HTMLDivElement>(null);
  const logoRef    = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const tl = gsap.timeline({ delay: 0.3 });

    tl.fromTo(logoRef.current,
      { opacity: 0, y: -12 },
      { opacity: 1, y: 0, duration: 0.8, ease: "power2.out" }
    )
    .fromTo(titleRef.current,
      { opacity: 0, y: 30, letterSpacing: "0.3em" },
      { opacity: 1, y: 0, letterSpacing: "0.12em", duration: 1.1, ease: "power3.out" },
      "-=0.3"
    )
    .fromTo(lineRef.current,
      { scaleX: 0 },
      { scaleX: 1, duration: 0.7, ease: "power2.inOut" },
      "-=0.5"
    )
    .fromTo(taglineRef.current,
      { opacity: 0, y: 14 },
      { opacity: 1, y: 0, duration: 0.7, ease: "power2.out" },
      "-=0.3"
    )
    .fromTo(ctaGroupRef.current,
      { opacity: 0, y: 18 },
      { opacity: 1, y: 0, duration: 0.65, ease: "power2.out" },
      "-=0.3"
    )
    .fromTo(scrollRef.current,
      { opacity: 0 },
      { opacity: 1, duration: 0.6 },
      "-=0.1"
    );
  }, []);

  return (
    <div className={styles.hero}>
      {/* ── Top-left logo ── */}
      <div ref={logoRef} className={styles.logoMark}>
        <span className={styles.logoIcon}>◈</span>
        <span className={styles.logoText}>Leaders Talk</span>
      </div>

      {/* ── Centered hero title ── */}
      <div className={styles.center}>
        <h1
          ref={titleRef}
          data-hero-title=""
          className={styles.title}
        >
          LEADERS TALK
        </h1>
        <div ref={lineRef} className={styles.line} />
        <p ref={taglineRef} className={styles.tagline}>
          Where visionary leaders shape tomorrow&apos;s conversations
        </p>

        {/* ── CTA Buttons ── */}
        <div ref={ctaGroupRef} className={styles.ctaGroup}>
          <a
            href="#section-5"
            className={styles.ctaPrimary}
            id="hero-cta-register"
          >
            Đăng ký ngay
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
              <path d="M2.5 7h9M8 3.5L11.5 7 8 10.5"
                stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </a>
          <a
            href="#section-4"
            className={styles.ctaSecondary}
            id="hero-cta-issues"
          >
            Những số khác
          </a>
        </div>
      </div>

      {/* ── Bottom scroll indicator ── */}
      <div ref={scrollRef} className={styles.scrollHint}>
        <div className={styles.scrollTrack}>
          <div className={styles.scrollDot} />
        </div>
        <span className={styles.scrollLabel}>Cuộn tiếp để khám phá</span>
      </div>
    </div>
  );
}
